internal final class ETGGMCController extends SrsReportRunController
{
}

Method.Source:
public static ETGGMCController construct()
{
    return new ETGGMCController();
}

public static void main(Args _args)
{
    ETGGMCController controller = new ETGGMCController();
    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGGMCReport, ReportNew));
    controller.parmDialogCaption("Gross margin by customer report");
    controller.startOperation();

}
